'use strict';

// MODULES //

import numelDimension from '@stdlib/ndarray/base/numel-dimension';
import getStride from '@stdlib/ndarray/base/stride';
import getOffset from '@stdlib/ndarray/base/offset';
import getData from '@stdlib/ndarray/base/data-buffer';
import { ndarray as strided } from './../../../../../ext/base/dzero-to';


// MAIN //

/**
* Fills a one-dimensional double-precision floating-point ndarray with linearly spaced numeric elements which increment by `1` starting from zero.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing a one-dimensional input ndarray
* @returns {ndarray} input ndarray
*
* @example
* import Float64Array from '@stdlib/array/float64';
* import ndarray from '@stdlib/ndarray/base/ctor';
*
* var xbuf = new Float64Array( [ 0.0, 0.0, 0.0, 0.0 ] );
* var x = new ndarray( 'float64', xbuf, [ 4 ], [ 1 ], 0, 'row-major' );
* // returns <ndarray>[ 0.0, 0.0, 0.0, 0.0 ]
*
* var out = dzeroTo( [ x ] );
* // returns <ndarray>[ 0.0, 1.0, 2.0, 3.0 ]
*/
function dzeroTo( arrays ) {
	var x = arrays[ 0 ];
	strided( numelDimension( x, 0 ), getData( x ), getStride( x, 0 ), getOffset( x ) ); // eslint-disable-line max-len
	return x;
}


// EXPORTS //

export default dzeroTo;
