'use strict';

// MODULES //

import isColumnMajor from '@stdlib/ndarray/base/assert/is-column-major';
import arraylike2object from '@stdlib/array/base/arraylike2object';
import ones from '@stdlib/array/base/ones';
import accessors from './accessors.js';


// MAIN //

/**
* Returns the index of the first column in an input matrix which has the same elements as a provided search vector.
*
* ## Notes
*
* -   If the function is provided an empty matrix or if the function is unable to find a search vector, the function returns `-1` (i.e., an invalid index).
*
* @private
* @param {PositiveInteger} M - number of rows in `A`
* @param {PositiveInteger} N - number of columns in `A`
* @param {Collection} A - input matrix
* @param {integer} strideA1 - stride of the first dimension of `A`
* @param {integer} strideA2 - stride of the second dimension of `A`
* @param {NonNegativeInteger} offsetA - index offset for `A`
* @param {Collection} x - search vector
* @param {integer} strideX - stride length for `x`
* @param {NonNegativeInteger} offsetX - index offset for `x`
* @returns {integer} column index
*
* @example
* var A = [ 1.0, 3.0, 0.0, 2.0, 4.0, 0.0 ]; // => [ [ 1.0, 3.0, 0.0 ], [ 2.0, 4.0, 0.0 ] ]
* var x = [ 3.0, 4.0 ];
*
* var out = gindexOfColumn( 2, 3, A, 3, 1, 0, x, 1, 0 );
* // returns 1
*
* @example
* var A = [ 1.0, 2.0, 3.0, 4.0, 0.0, 0.0 ]; // => [ [ 1.0, 3.0, 0.0 ], [ 2.0, 4.0, 0.0 ] ]
* var x = [ 3.0, 4.0 ];
*
* var out = gindexOfColumn( 2, 3, A, 1, 2, 0, x, 1, 0 );
* // returns 1
*
* @example
* var A = [ 1.0, 2.0, 3.0, 4.0, 0.0, 0.0 ]; // => [ [ 1.0, 3.0, 0.0 ], [ 2.0, 4.0, 0.0 ] ]
* var x = [ 1.0, 2.0 ];
*
* var out = gindexOfColumn( 2, 3, A, 1, 2, 0, x, 1, 0 );
* // returns 0
*
* @example
* var A = [ 1.0, 2.0, 3.0, 4.0, 0.0, 0.0 ]; // => [ [ 1.0, 3.0, 0.0 ], [ 2.0, 4.0, 0.0 ] ]
* var x = [ 0.0, 0.0 ];
*
* var out = gindexOfColumn( 2, 3, A, 1, 2, 0, x, 1, 0 );
* // returns 2
*
* @example
* var A = [ 1.0, 2.0, 3.0, 4.0, 0.0, 0.0 ]; // => [ [ 1.0, 3.0, 0.0 ], [ 2.0, 4.0, 0.0 ] ]
* var x = [ -3.0, -4.0 ];
*
* var out = gindexOfColumn( 2, 3, A, 1, 2, 0, x, 1, 0 );
* // returns -1
*/
function gindexOfColumn( M, N, A, strideA1, strideA2, offsetA, x, strideX, offsetX ) { // eslint-disable-line max-len
	var matches;
	var da0;
	var da1;
	var S0;
	var S1;
	var ia;
	var ix;
	var i0;
	var i1;
	var oa;
	var ox;

	// Check whether the matrix is an empty matrix...
	if ( M <= 0 || N <= 0 ) {
		return -1;
	}
	oa = arraylike2object( A );
	ox = arraylike2object( x );
	if ( oa.accessorProtocol || ox.accessorProtocol ) {
		return accessors( M, N, oa, strideA1, strideA2, offsetA, ox, strideX, offsetX ); // eslint-disable-line max-len
	}
	// Search for the first column matching the search vector...
	if ( isColumnMajor( [ strideA1, strideA2 ] ) ) {
		S0 = M;
		S1 = N;

		// Scan a column-major linear buffer from the first indexed element to the last indexed element, always moving in the same direction when both strides are the same sign, thus ensuring cache optimal traversal...
		for ( i1 = 0; i1 < S1; i1++ ) {
			ia = offsetA + ( i1*strideA2 );
			ix = offsetX;
			for ( i0 = 0; i0 < S0; i0++ ) {
				if ( A[ ia ] !== x[ ix ] ) {
					// We found an element which is not in the search vector...
					break;
				}
				ia += strideA1;
				ix += strideX;
			}
			// If we successfully iterated over all rows, then that means we've found a match...
			if ( i0 === S0 ) {
				return i1;
			}
		}
		// If we've made it here, then no columns match the search vector:
		return -1;
	}
	// Row-major...
	S0 = N;
	S1 = M;

	// Resolve loop offset (pointer) increments:
	da0 = strideA2;
	da1 = strideA1 - ( S0*strideA2 );

	// Create an array for tracking which columns contain matching elements:
	matches = ones( N );

	// Finding the first matching column when a matrix is stored in row-major order requires effectively performing a full linear scan. In order to ensure cache-efficient traversal, scan across each row (otherwise, if we went column-by-column, we'd hop around linear memory, resulting in poor cache behavior)...
	ia = offsetA;
	ix = offsetX;
	for ( i1 = 0; i1 < S1; i1++ ) {
		// Scan across the columns in a row looking for a matching element...
		for ( i0 = 0; i0 < S0; i0++ ) {
			if ( A[ ia ] !== x[ ix ] ) {
				// We found a non-matching element, which means we can exclude this column from the list of column candidates...
				matches[ i0 ] = 0;
			}
			ia += da0;
		}
		ia += da1;
		ix += strideX;
	}
	// Search for the first matching column...
	for ( i0 = 0; i0 < S0; i0++ ) {
		if ( matches[ i0 ] === 1 ) {
			break;
		}
	}
	return ( i0 === S0 ) ? -1 : i0;
}


// EXPORTS //

export default gindexOfColumn;
